import React, { useState } from "react";
import jsPDF from "jspdf";

export default function ResumeChatbot() {
  const [messages, setMessages] = useState([
    { role: "bot", text: "Hi! I will help you build your resume 🤖" }
  ]);
  const [step, setStep] = useState(0);
  const [input, setInput] = useState("");

  const [formData, setFormData] = useState({
    name: "",
    role: "",
    education: "",
    skills: "",
    projects: ""
  });

  const questions = [
    "What is your full name?",
    "What role are you targeting?",
    "Tell me your education",
    "List your skills (comma separated)",
    "Tell me your projects"
  ];

  const keys = Object.keys(formData);

  const handleSend = () => {
    if (!input) return;

    const newMessages = [...messages, { role: "user", text: input }];

    // store input
    const updatedData = { ...formData, [keys[step]]: input };
    setFormData(updatedData);

    let nextMessages = [...newMessages];

    if (step < questions.length - 1) {
      nextMessages.push({ role: "bot", text: questions[step + 1] });
      setStep(step + 1);
    } else {
      nextMessages.push({
        role: "bot",
        text: "Great! Generating your professional resume..."
      });
    }

    setMessages(nextMessages);
    setInput("");
  };

  const generateResume = () => {
    return {
      ...formData,
      skills: formData.skills.split(","),
      projects: formData.projects.split(",")
    };
  };

  const downloadPDF = () => {
    const data = generateResume();
    const doc = new jsPDF();

    let y = 20;

    doc.setFontSize(18);
    doc.text(data.name, 10, y);
    y += 10;

    doc.setFontSize(12);
    doc.text(data.role, 10, y);
    y += 10;

    doc.line(10, y, 200, y);
    y += 10;

    doc.setFontSize(14);
    doc.text("Education", 10, y);
    y += 8;
    doc.setFontSize(11);
    doc.text(data.education, 10, y);
    y += 10;

    doc.setFontSize(14);
    doc.text("Skills", 10, y);
    y += 8;
    data.skills.forEach(s => {
      doc.text("• " + s.trim(), 10, y);
      y += 6;
    });

    y += 5;

    doc.setFontSize(14);
    doc.text("Projects", 10, y);
    y += 8;
    data.projects.forEach(p => {
      doc.text("• " + p.trim(), 10, y);
      y += 6;
    });

    doc.save("Resume.pdf");
  };

  const resume = generateResume();

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      background: "linear-gradient(135deg, #1e3c72, #2a5298)"
    }}>

      <div style={{
        width: "600px",
        backdropFilter: "blur(15px)",
        background: "rgba(255,255,255,0.1)",
        borderRadius: "20px",
        padding: "20px",
        color: "white"
      }}>

        <h2 style={{ textAlign: "center" }}>🤖 AI Resume Chatbot</h2>

        {/* CHAT AREA */}
        <div style={{
          height: "300px",
          overflowY: "auto",
          marginBottom: "10px"
        }}>
          {messages.map((m, i) => (
            <div key={i} style={{ textAlign: m.role === "user" ? "right" : "left" }}>
              <p>{m.text}</p>
            </div>
          ))}
        </div>

        {/* INPUT */}
        {step < questions.length && (
          <div style={{ display: "flex" }}>
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={questions[step]}
              style={{ flex: 1, padding: "10px", borderRadius: "10px" }}
            />
            <button onClick={handleSend} style={{ marginLeft: "10px" }}>Send</button>
          </div>
        )}

        {/* RESULT */}
        {step === questions.length - 1 && formData.projects && (
          <>
            <div style={{ background: "white", color: "black", marginTop: "10px", padding: "10px" }}>
              <h3>{resume.name}</h3>
              <p>{resume.role}</p>
              <p>{resume.education}</p>
            </div>
            <button onClick={downloadPDF}>Download PDF</button>
          </>
        )}

      </div>
    </div>
  );
}
